import{_ as a,o as e,c as r,a4 as o}from"./chunks/framework.BybBnFXO.js";const c=JSON.parse('{"title":"磷酸盐","description":"","frontmatter":{"title":"磷酸盐","mineralGroup":"phosphates"},"headers":[],"relativePath":"zh/mineral-groups/phosphates.md","filePath":"zh/mineral-groups/phosphates.md","lastUpdated":1784176423000}'),i={name:"zh/mineral-groups/phosphates.md"};function l(d,t,s,h,n,p){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="磷酸盐" tabindex="-1">磷酸盐 <a class="header-anchor" href="#磷酸盐" aria-label="Permalink to &quot;磷酸盐&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>磷酸盐类是玉石与生物质宝石的主要来源：</p><ul><li><strong>磷灰石族</strong>：含羟基磷灰石、氟磷灰石、氯磷灰石、磷氯铅矿</li><li><strong>绿松石</strong>：铜铝磷酸盐，多孔结构（土耳其石的核心致色机理）</li><li><strong>天蓝石</strong>：与绿松石共生的蓝色磷酸盐矿物</li><li><strong>磷铝石（巴西石）</strong></li><li><strong>独居石、磷钇矿</strong>（含放射性元素）</li></ul><h2 id="化学式类型" tabindex="-1">化学式类型 <a class="header-anchor" href="#化学式类型" aria-label="Permalink to &quot;化学式类型&quot;">​</a></h2><p>PO₄³⁻ 基团 + 金属阳离子</p><h2 id="结构" tabindex="-1">结构 <a class="header-anchor" href="#结构" aria-label="Permalink to &quot;结构&quot;">​</a></h2><p>[PO₄]³⁻ 四面体独立或与其他四面体（[OH]⁻、[F]⁻）共顶点连接。金 属阳离子（Ca、Fe、Mn、Al、Li、Be、Cu）与 P 形成稳定配位。 磷灰石族为六方晶系，绿松石为三斜晶系。</p><h2 id="代表性宝石" tabindex="-1">代表性宝石 <a class="header-anchor" href="#代表性宝石" aria-label="Permalink to &quot;代表性宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>化学式</th><th>亚族</th></tr></thead><tbody><tr><td>Apatite / 磷灰石</td><td>Ca₅(PO₄)₃(F,OH,Cl)</td><td>apatite</td></tr><tr><td>Turquoise / 绿松石</td><td>CuAl₆(PO₄)₄(OH)₈·4H₂O</td><td>turquoise</td></tr><tr><td>Lazulite / 天蓝石</td><td>(Mg,Fe)Al₂(PO₄)₂(OH)₂</td><td>lazulite</td></tr><tr><td>Brazilianite / 磷铝石</td><td>NaAl₃(PO₄)₂(OH)₄</td><td>brazilianite</td></tr></tbody></table><p><em>详见<a href="./intro.html">矿物组总览</a>。</em></p>',11)])])}const m=a(i,[["render",l]]);export{c as __pageData,m as default};
